patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..2a2e621f251b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1872,9 +1872,28 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return replaceInstUsesWith(I, Builder.CreateZExtOrTrunc(Ret, I.getType()));
   }

+
+  // Fold (X >> C) + (zext (icmp ne (and X, (1<<C)-1), 0)) -> (X + (1<<C)-1) >> C
+  const APInt *ShAmt, *Mask;
+  Value *X;
+  CmpPredicate CeilPred;
+  if (match(&I, m_c_Add(m_OneUse(m_LShr(m_Value(X), m_APInt(ShAmt))),
+                         m_OneUse(m_ZExt(m_OneUse(m_ICmp(CeilPred,
+                             m_OneUse(m_And(m_Deferred(X), m_APInt(Mask))),
+                             m_Zero())))))) &&
+      CeilPred == ICmpInst::ICMP_NE) {
+    if (!ShAmt->isZero() &&
+        *Mask == (APInt(ShAmt->getBitWidth(), 1) << *ShAmt) - 1) {
+      Value *NewAdd = Builder.CreateAdd(
+          X, ConstantInt::get(X->getType(), *Mask), "",
+          I.hasNoUnsignedWrap(), I.hasNoSignedWrap());
+      return BinaryOperator::CreateLShr(
+          NewAdd, ConstantInt::get(X->getType(), *ShAmt));
+    }
+  }
+
   if (Instruction *Res = foldSquareSumInt(I))
     return Res;
-
   if (Instruction *Res = foldBinOpOfDisplacedShifts(I))
     return Res;

